export const DEFAULT_CONSISTENCY_CONFIG={threshold:80,useFeatureVector:!0,vectorSimilarityThreshold:.85};export class StubFaceEmbeddingProvider{dimension;constructor(e=0){this.dimension=e}async extract(e){return this.dimension>0?new Array(this.dimension).fill(0):[]}}export class CharacterConsistencyChecker{library;config;provider;constructor(e,r,t){this.library=e,this.config={...DEFAULT_CONSISTENCY_CONFIG,...r},this.provider=t??new StubFaceEmbeddingProvider}async checkFrame(e,r){const t=this.library.getCharacter(r);if(!t)return this.failure(0,`Character not found: ${r}`);if(!this.config.useFeatureVector)return this.skip(t,"Feature-vector comparison is disabled in the current configuration.");const s=t.featureVector;if(!s||s.length===0)return this.skip(t,`Character "${t.name}" has no feature vector. Call extractFeatureVector and setFeatureVector first to enable consistency checking.`);const o=await this.extractFeatureVector(e);if(o.length===0)return this.skip(t,"Face-embedding provider returned an empty vector for the frame. This usually means no face was detected or no real provider is configured.");const i=CharacterConsistencyChecker.cosineSimilarity(o,s),n=Math.round(Math.max(0,Math.min(1,i))*100),c=[];i<this.config.vectorSimilarityThreshold&&c.push({severity:i<.5?"critical":"major",type:"face_mismatch",description:`Face embedding similarity (${i.toFixed(4)}) is below the threshold (${this.config.vectorSimilarityThreshold}).`,fixInstruction:"Reroll the clip with the character's reference image as the first/last frame, or tighten the prompt's appearance description."});const l=n>=this.config.threshold,a=l?void 0:`Frame score ${n}/100 is below the threshold ${this.config.threshold}. Consider rerolling with a stronger reference-image anchor.`;return{score:n,passed:l,issues:c,suggestion:a}}async checkFrames(e,r){if(e.length===0)return this.failure(0,"No frames provided for consistency check.");const t=await Promise.all(e.map(a=>this.checkFrame(a,r)));let s=1/0;const o=[],i=[];for(const a of t)a.score<s&&(s=a.score),o.push(...a.issues),a.suggestion&&i.push(a.suggestion);const n=s===1/0?0:s,c=n>=this.config.threshold,l=i.length>0?`${i.length} frame(s) flagged: ${i[0]}`:void 0;return{score:n,passed:c,issues:o,suggestion:l}}async extractFeatureVector(e){return this.provider.extract(e)}static cosineSimilarity(e,r){if(e.length===0||e.length!==r.length)return 0;let t=0,s=0,o=0;for(let n=0;n<e.length;n++)t+=e[n]*r[n],s+=e[n]*e[n],o+=r[n]*r[n];const i=Math.sqrt(s)*Math.sqrt(o);return i===0?0:t/i}static generateThreeViewPrompt(e){const r=e.ageRange||"25",t=e.gender,s=e.appearance||"average build",o=e.clothing||"casual clothing",i="studio lighting, white background, high detail, consistent character design, concept art style, character reference sheet, sharp focus, anatomically correct";return{front:`Character sheet, front view, full body portrait of a ${r} year old ${t}, ${s}, wearing ${o}, neutral expression, facing forward, standing pose, ${i}`,side:`Character sheet, side profile view, full body portrait of a ${r} year old ${t}, ${s}, wearing ${o}, neutral expression, exact 90-degree side profile, standing pose, ${i}`,back:`Character sheet, back view, full body portrait of a ${r} year old ${t}, ${s}, wearing ${o}, standing pose, viewed from directly behind, ${i}`}}static generateReferenceImagePrompt(e,r){const t=e.ageRange||"25",s=e.gender,o=e.appearance||"average build",i=e.clothing||"casual clothing",n="studio lighting, high detail, consistent character design, concept art style, sharp focus";switch(r){case"portrait":return`Portrait headshot of a ${t} year old ${s}, ${o}, wearing ${i}, neutral expression, looking at camera, head and shoulders framing, ${n}`;case"full_body":return`Full body standing portrait of a ${t} year old ${s}, ${o}, wearing ${i}, neutral expression, front-facing, full body visible head to toe, white background, ${n}`;case"action":return`Action shot of a ${t} year old ${s}, ${o}, wearing ${i}, dynamic mid-motion pose, dramatic lighting, motion blur on extremities, cinematic composition, ${n}`;case"expression":return`Facial expression close-up of a ${t} year old ${s}, ${o}, wearing ${i}, expressive emotion, face fills the frame, detailed facial features, ${n}`;default:return`Reference image of a ${t} year old ${s}, ${o}, wearing ${i}, ${n}`}}skip(e,r){return{score:0,passed:0>=this.config.threshold,issues:[],suggestion:`[Skipped] Character "${e.name}": ${r}`}}failure(e,r){return{score:e,passed:e>=this.config.threshold,issues:[{severity:"critical",type:"face_mismatch",description:r}],suggestion:r}}}
